const s=document.querySelector("#style"),fn=document.querySelector("#firstname"),ln=document.querySelector("#lastname"),j=document.querySelector("#job"),e=document.querySelector("#email"),f=document.querySelector("#preview"),getName=()=>`${fn.value} ${ln.value}`.trim(),getEmail=()=>{const base=e.value.trim()||`${fn.value.toLowerCase()}.${ln.value.toLowerCase()}`.replace(/\s+/g,'');return base.includes('@')?base:`${base}@groupe-speed.cloud`},c=()=>{if(!s.value)return;f.removeAttribute("srcdoc");f.src=`./templates/${encodeURIComponent(s.value)}.html?name=${encodeURIComponent(getName())}&job=${encodeURIComponent(j.value)}&email=${encodeURIComponent(getEmail())}`};s.addEventListener("change",(()=>{c();if(s.value==="chatwoot"){e.parentElement.parentElement.style.opacity="0.5"}else{e.parentElement.parentElement.style.opacity="1"}}));[fn,ln,j,e].forEach(t=>t.addEventListener("keyup",c));[fn,ln].forEach(t=>t.addEventListener("keyup",()=>{if(!e.value){e.placeholder=`${fn.value.toLowerCase()}.${ln.value.toLowerCase()}`.replace(/\s+/g,'')}}))